def gen(rng, size):
    n = max(1, min(size, 50000))
    if n % 2 == 1:
        n -= 1
    if n == 0:
        n = 2
    if rng.randint(0, 1) == 0:
        target = rng.randint(2, 1000)
        skill = []
        for _ in range(n // 2):
            lo = max(1, target - 1000)
            hi = min(999, target - 1)
            if lo > hi:
                a = target // 2 if target // 2 >= 1 else 1
            else:
                a = rng.randint(lo, hi)
            b = target - a
            if b < 1 or b > 1000:
                a = 1
                b = target - 1
            skill.append(a)
            skill.append(b)
    else:
        skill = [rng.randint(1, 1000) for _ in range(n)]
    return [skill]

