class Solution:
    def dividePlayers(self, skill):
        n = len(skill)
        total = sum(skill)
        if total % (n // 2) != 0:
            return -1
        target = total // (n // 2)
        remaining = list(skill)
        chemistry = 0
        while remaining:
            a = remaining.pop()
            found = False
            for i in range(len(remaining)):
                if a + remaining[i] == target:
                    chemistry += a * remaining[i]
                    remaining.pop(i)
                    found = True
                    break
            if not found:
                return -1
        return chemistry

