var dividePlayers = function(skill) {
    const sorted = skill.slice().sort((a, b) => a - b);
    const n = sorted.length;
    const target = sorted[0] + sorted[n - 1];
    let chemistry = 0;
    let left = 0, right = n - 1;
    while (left < right) {
        if (sorted[left] + sorted[right] !== target) {
            return -1;
        }
        chemistry += sorted[left] * sorted[right];
        left += 1;
        right -= 1;
    }
    return chemistry;
};
